"use client";

import Image from "next/image";
import Link from "next/link";

interface ShopCard {
  id: string;
  image: string;
  title: string;
  buttonText: string;
  buttonUrl: string;
  badge?: {
    enabled: boolean;
    value: string;
    label: string;
  };
}

interface DynamicShopBySectionProps {
  data: {
    cards: ShopCard[];
  };
}

export function DynamicShopBySection({ data }: DynamicShopBySectionProps) {
  if (!data.cards || data.cards.length === 0) {
    return null;
  }

  return (
    <section className="w-full bg-white py-16 md:py-24">
      <div className="mx-auto w-full max-w-[1400px] px-4 md:px-6">
        <h2 className="mb-12 text-4xl font-bold text-gray-900">
          Shop By Category
        </h2>

        <div className="grid gap-8 md:grid-cols-2 lg:grid-cols-3">
          {data.cards.map((card) => (
            <div
              key={card.id}
              className="group relative overflow-hidden rounded-lg bg-gray-50 transition-all hover:shadow-lg"
            >
              {/* Image Container */}
              <div className="relative h-64 w-full overflow-hidden bg-gray-100">
                <Image
                  src={card.image}
                  alt={card.title}
                  fill
                  className="object-cover transition-transform duration-300 group-hover:scale-105"
                />

                {/* Badge */}
                {card.badge?.enabled && (
                  <div className="absolute right-4 top-4 rounded-lg bg-orange-500 px-3 py-2 text-white">
                    <div className="text-lg font-bold">{card.badge.value}</div>
                    <div className="text-xs">{card.badge.label}</div>
                  </div>
                )}
              </div>

              {/* Content */}
              <div className="p-6">
                <h3 className="mb-4 text-xl font-semibold text-gray-900">
                  {card.title}
                </h3>

                <Link
                  href={card.buttonUrl}
                  className="inline-block rounded-lg bg-gradient-to-r from-orange-400 to-orange-500 px-6 py-2 font-medium text-white transition-all hover:from-orange-500 hover:to-orange-600"
                >
                  {card.buttonText}
                </Link>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
