"use client";

import Image from "next/image";
import Link from "next/link";

interface Category {
  id: string;
  name: string;
  image: string;
  href: string;
}

interface DynamicCategoriesSectionProps {
  data: {
    sectionTitle: string;
    items: Category[];
  };
}

export function DynamicCategoriesSection({ data }: DynamicCategoriesSectionProps) {
  if (!data.items || data.items.length === 0) {
    return null;
  }

  return (
    <section className="w-full bg-white py-16 md:py-24">
      <div className="mx-auto w-full max-w-[1400px] px-4 md:px-6">
        <h2 className="mb-12 text-4xl font-bold text-gray-900">
          {data.sectionTitle}
        </h2>

        <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-4">
          {data.items.map((category) => (
            <Link
              key={category.id}
              href={category.href}
              className="group relative overflow-hidden rounded-lg"
            >
              <div className="relative h-64 w-full overflow-hidden bg-gray-100">
                <Image
                  src={category.image}
                  alt={category.name}
                  fill
                  className="object-cover transition-transform duration-300 group-hover:scale-110"
                />
                <div className="absolute inset-0 bg-black/40 transition-all group-hover:bg-black/50" />
              </div>

              <div className="absolute inset-0 flex items-center justify-center">
                <h3 className="text-center text-2xl font-bold text-white">
                  {category.name}
                </h3>
              </div>
            </Link>
          ))}
        </div>
      </div>
    </section>
  );
}
